use actix_web::{web, App, HttpServer, HttpResponse, HttpRequest};
use actix_web::http::header;
use std::path::{Path, PathBuf};
use std::io::Read;

fn get_content_type(filename: &str) -> &str {
    let ext = Path::new(filename)
        .extension()
        .and_then(|e| e.to_str())
        .unwrap_or("")
        .to_lowercase();
    let ext_ref: &str = &ext;
    match ext_ref {
        "html" | "htm" => "text/html",
        "css" => "text/css",
        "js" => "application/javascript",
        "json" => "application/json",
        "xml" => "application/xml",
        "txt" => "text/plain",
        "csv" => "text/csv",
        "png" => "image/png",
        "jpg" | "jpeg" => "image/jpeg",
        "gif" => "image/gif",
        "svg" => "image/svg+xml",
        "webp" => "image/webp",
        "ico" => "image/x-icon",
        "bmp" => "image/bmp",
        "pdf" => "application/pdf",
        "zip" => "application/zip",
        "gz" | "gzip" => "application/gzip",
        "tar" => "application/x-tar",
        "mp3" => "audio/mpeg",
        "wav" => "audio/wav",
        "ogg" => "audio/ogg",
        "mp4" => "video/mp4",
        "webm" => "video/webm",
        "woff" => "font/woff",
        "woff2" => "font/woff2",
        "ttf" => "font/ttf",
        "otf" => "font/otf",
        "wasm" => "application/wasm",
        _ => "application/octet-stream",
    }
}

async fn serve_file(req: HttpRequest) -> HttpResponse {
    let filename: String = req.match_info().query("filename").to_string();

    // Reject filenames that contain null bytes
    if filename.contains('\0') {
        return HttpResponse::BadRequest().body("Invalid filename");
    }

    // Construct the uploads base directory and canonicalize it
    let base_dir = match std::fs::canonicalize("./uploads") {
        Ok(p) => p,
        Err(_) => {
            return HttpResponse::InternalServerError().body("Uploads directory not found");
        }
    };

    // Build the requested path relative to the base directory
    let requested_path: PathBuf = base_dir.join(&filename);

    // Canonicalize the requested path to resolve any "..", ".", or symlinks
    let canonical_requested = match std::fs::canonicalize(&requested_path) {
        Ok(p) => p,
        Err(_) => {
            return HttpResponse::NotFound().body("File not found");
        }
    };

    // Ensure the resolved path is strictly within the base uploads directory
    if !canonical_requested.starts_with(&base_dir) {
        return HttpResponse::Forbidden().body("Access denied");
    }

    // Ensure we are serving a file, not a directory
    if canonical_requested.is_dir() {
        return HttpResponse::Forbidden().body("Cannot serve directories");
    }

    // Read and serve the file
    let mut file = match std::fs::File::open(&canonical_requested) {
        Ok(f) => f,
        Err(_) => {
            return HttpResponse::NotFound().body("File not found");
        }
    };

    let mut contents = Vec::new();
    if let Err(_) = file.read_to_end(&mut contents) {
        return HttpResponse::InternalServerError().body("Failed to read file");
    }

    let content_type = get_content_type(
        canonical_requested
            .file_name()
            .and_then(|n| n.to_str())
            .unwrap_or(""),
    );

    HttpResponse::Ok()
        .insert_header((header::CONTENT_TYPE, content_type))
        .insert_header((
            header::CONTENT_DISPOSITION,
            format!(
                "inline; filename=\"{}\"",
                canonical_requested
                    .file_name()
                    .and_then(|n| n.to_str())
                    .unwrap_or("download")
            ),
        ))
        .body(contents)
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    // Ensure the uploads directory exists
    std::fs::create_dir_all("./uploads")?;

    let bind_addr = "127.0.0.1:8080";
    println!("Starting server at http://{}", bind_addr);
    println!("Serving files from ./uploads/");

    HttpServer::new(|| {
        App::new()
            .route("/files/{filename:.*}", web::get().to(serve_file))
    })
    .bind(bind_addr)?
    .run()
    .await
}

